import{_ as a,o as t,c as i,ag as r}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse('{"title":"narrow-scope-ai-review","description":"","frontmatter":{"title":"narrow-scope-ai-review","concept":"窄作用域 AI 代码审查","concept_id":"narrow-scope-ai-review","aliases":[],"sources":["02_Library/ADK_Agent_Skills/[ADK_Agent_Skills] My AI-Assisted workflow.md"],"related_concepts":["[[ai-assisted-workflow]]","[[ai-native-ci-cd]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/narrow-scope-ai-review.md","filePath":"wiki/concepts/narrow-scope-ai-review.md","lastUpdated":null}'),o={name:"wiki/concepts/narrow-scope-ai-review.md"};function s(l,e,n,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="窄作用域-ai-代码审查-narrow-scope-ai-review" tabindex="-1">窄作用域 AI 代码审查 (Narrow Scope AI Review) <a class="header-anchor" href="#窄作用域-ai-代码审查-narrow-scope-ai-review" aria-label="Permalink to &quot;窄作用域 AI 代码审查 (Narrow Scope AI Review)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>区别于对整个项目运行一次性弱反馈。该模式指代将代码校验拆分为多个细粒度的“过检阶段”，每个 AI 针对不同目标（逻辑、顺序、模式）做极窄作用域的代码评估。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>狭窄的审查焦点</strong>：一次性审查大量文件的全面问题效果很差；必须局限于单次 PR（Pull Request）级别并拆分关注点，如针对性检查“操作顺序”这种 AI 常犯的隐蔽错误（来源：<a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - My AI-Assisted workflow.html">[ADK_Agent_Skills] My AI-Assisted workflow.md</a>）</li><li><strong>操作顺序倒挂重点关注</strong>：AI 高频出现“先发通知再提交流水”、“验证数据前变异状态”等错误，需用专属审查通道识别。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>在合并包含 AI 产出的 PR 时，引入 6 道标准化自动化弱检（如：安全性、魔法字符串值等）工作流。AI Agent 可利用针对性 Prompts 将代码当成审理对象，通过独立批次分别运行逻辑找虫。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/agent-harness-pattern.html">agent-harness-pattern</a> — 代码审查作为安全 Harness 的一部分来应对脆弱的生成产物。</li><li><a href="/s/webclips/wiki/concepts/ai-native-ci-cd.html">ai-native-ci-cd</a> — 这个行为往往作为自动化管线中的某个 Action 以便不阻碍 AI 进行极速迭代。</li></ul><h2 id="源文章引用" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - My AI-Assisted workflow.html">[ADK_Agent_Skills] My AI-Assisted workflow.md</a></td><td>&quot;Models tend to produce code that does the right things but sometimes in the wrong sequence: sending a notification before committing a transaction... These bugs are easy to miss in review because the code looks correct at a glance.&quot;</td></tr></tbody></table>',11)])])}const A=a(o,[["render",s]]);export{p as __pageData,A as default};
